-- truncate table menu restart identity;


-- Сдвигаем счётчик автонумерации id за максимум, чтобы новые блюда
-- (если будешь добавлять через БД) не конфликтовали по id.
select setval(pg_get_serial_sequence('menu','id'), (select max(id) from menu));
